window.addEventListener("load", function () {
  const e = document.getElementById("loading-screen");
  e &&
    setTimeout(() => {
      e.classList.add("hidden");
    }, 2600);
});
function debounce(e, t) {
  let n;
  return function (...o) {
    (clearTimeout(n),
      (n = setTimeout(() => {
        (clearTimeout(n), e(...o));
      }, t)));
  };
}
document.addEventListener("DOMContentLoaded", function () {
  const e = document.querySelector(".nav-toggle"),
    t = document.querySelector(".nav-links"),
    n = document.querySelectorAll(".nav-links a");
  (e &&
    e.addEventListener("click", function (o) {
      (o.stopPropagation(),
        e.classList.toggle("active"),
        t.classList.toggle("active"));
    }),
    n.forEach((e) => {
      e.addEventListener("click", function () {
        (e.classList.remove("active"), t.classList.remove("active"));
      });
    }),
    document.addEventListener("click", function (o) {
      if (t && t.classList.contains("active")) {
        const a = t.contains(o.target),
          s = e && e.contains(o.target);
        a || s || (e.classList.remove("active"), t.classList.remove("active"));
      }
    }),
    window.addEventListener(
      "resize",
      debounce(function () {
        window.innerWidth > 768 &&
          (e && e.classList.remove("active"),
          t && t.classList.remove("active"));
      }, 200),
    ));
  const o = document.getElementById("contact-form");
  o &&
    o.addEventListener("submit", function (a) {
      a.preventDefault();
      const s = document.getElementById("name").value.trim(),
        l = document.getElementById("email").value.trim(),
        c = document.getElementById("message").value.trim();
      if (s && l && c) {
        const i = `Hello, my name is ${s}.\nEmail: ${l}\n\nMessage: ${c}`,
          d = encodeURIComponent(i),
          u = `https://wa.me/233534078670?text=${d}`,
          m = document.querySelector(".Alert");
        (m && m.classList.add("open"),
          o.reset(),
          window.open &&
            setTimeout(() => {
              window.open(u, "_blank", "noopener,noreferrer");
            }, 300),
          setTimeout(() => {
            m && m.classList.remove("open");
          }, 3e3));
      }
    });
});
